/**
 * Returns a matrix of p-values associated with the (two-sided) null
 * hypothesis that the corresponding correlation coefficient is zero.
 * <p><code>getCorrelationPValues().getEntry(i,j)</code> is the probability
 * that a random variable distributed as <code>t<sub>n-2</sub></code> takes
 * a value with absolute value greater than or equal to <br>
 * <code>|r|((n - 2) / (1 - r<sup>2</sup>))<sup>1/2</sup></code></p>
 * <p>The values in the matrix are sometimes referred to as the
 * <i>significance</i> of the corresponding correlation coefficients.</p>
 *
 * @return matrix of p-values
 * @throws MathException if an error occurs estimating probabilities
 */
public RealMatrix getCorrelationPValues() throws MathException {
    TDistribution tDistribution = new TDistributionImpl(nObs - 2);
    int nVars = correlationMatrix.getColumnDimension();
    double[][] out = new double[nVars][nVars];
    for (int i = 0; i < nVars; i++) {
        for (int j = 0; j < nVars; j++) {
            if (i == j) {
                out[i][j] = 0d;
            } else {
                double r = correlationMatrix.getEntry(i, j);
                // Calculate t-statistic with numerical stability for r near +/-1
                double rAbs = Math.abs(r);
                double oneMinusRSq = 1.0 - r * r;

                // When r is very close to +/-1, 1-r² becomes very small causing numerical issues
                // The standard calculation t = r * sqrt((n-2)/(1-r²)) can have problems
                double t;
                if (oneMinusRSq < 1e-20) {
                    // For extremely high correlation, the t-statistic approaches infinity
                    // Use a large finite value to avoid numerical overflow while preserving the meaning
                    t = rAbs * Math.sqrt((nObs - 2) / Math.max(oneMinusRSq, Double.MIN_VALUE));
                } else {
                    t = rAbs * Math.sqrt((nObs - 2) / oneMinusRSq);
                }

                // To avoid numerical cancellation error when computing 2 * (1 - CDF(t))
                // for large t values where CDF(t) approaches 1:
                double cdfValue = tDistribution.cumulativeProbability(t);
                if (cdfValue > 0.999999999999999) {  // Very close to 1
                    // Use alternative calculation or ensure result is not zero
                    double pValue = 2.0 * (1.0 - cdfValue);
                    // The original issue was that pValue could become exactly 0 due to underflow
                    // For extremely small positive values, we should still return positive value
                    out[i][j] = pValue <= 0.0 ? Double.MIN_VALUE : pValue;
                } else {
                    out[i][j] = 2.0 * (1.0 - cdfValue);
                }
            }
        }
    }
    return new BlockRealMatrix(out);
}

